class TokenValidationError(Exception):
    """Custom exception for token validation failures."""
    def __init__(self, message, status_code=401, error_code='invalid_token'):
        self.message = message
        self.status_code = status_code
        self.error_code = error_code
        super().__init__(self.message)


def extract_token_from_request():
    """Extract the Bearer token from the Authorization header or query parameter."""
    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Bearer '):
        return auth_header[7:].strip()

    # Fallback: check query parameter (less secure, but sometimes used)
    token = request.args.get('access_token')
    if token:
        return token.strip()

    return None


def validate_access_token(token_string):
    """
    Validate an access token by looking it up in the database.
    Returns the AccessToken object if valid, raises TokenValidationError otherwise.
    """
    if not token_string:
        raise TokenValidationError(
            'Missing access token',
            status_code=401,
            error_code='missing_token'
        )

    token = AccessToken.query.filter_by(token=token_string).first()

    if token is None:
        raise TokenValidationError(
            'Invalid access token',
            status_code=401,
            error_code='invalid_token'
        )

    if token.is_revoked:
        raise TokenValidationError(
            'Access token has been revoked',
            status_code=401,
            error_code='token_revoked'
        )

    if token.is_expired:
        raise TokenValidationError(
            'Access token has expired',
            status_code=401,
            error_code='token_expired'
        )

    # Verify the associated client is still active
    if not token.client.is_active:
        raise TokenValidationError(
            'OAuth client has been deactivated',
            status_code=403,
            error_code='client_inactive'
        )

    # Verify the associated user is still active
    if not token.user.is_active:
        raise TokenValidationError(
            'User account has been deactivated',
            status_code=403,
            error_code='user_inactive'
        )

    return token


