def require_oauth(*required_scopes):
    """
    Decorator to protect API endpoints with OAuth 2.0 token validation.

    Usage:
        @require_oauth()                    # just requires a valid token
        @require_oauth('read')              # requires 'read' scope
        @require_oauth('read', 'write')     # requires both 'read' AND 'write' scopes
    """
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            token_string = extract_token_from_request()

            try:
                token = validate_access_token(token_string)
            except TokenValidationError as e:
                return jsonify({
                    'error': e.error_code,
                    'error_description': e.message,
                }), e.status_code, {
                    'WWW-Authenticate': f'Bearer error="{e.error_code}", error_description="{e.message}"'
                }

            # Check required scopes
            for scope in required_scopes:
                if not token.has_scope(scope):
                    return jsonify({
                        'error': 'insufficient_scope',
                        'error_description': f'Required scope "{scope}" not granted',
                        'required_scopes': list(required_scopes),
                        'granted_scopes': token.scope_list,
                    }), 403, {
                        'WWW-Authenticate': f'Bearer error="insufficient_scope", scope="{" ".join(required_scopes)}"'
                    }

            # Store token info in Flask's g object for use in the endpoint
            g.current_token = token
            g.current_user = token.user
            g.current_client = token.client

            return f(*args, **kwargs)
        return decorated_function
    return decorator


