@app.route('/oauth/token/validate', methods=['POST'])
def validate_token_endpoint():
    """
    Token introspection / validation endpoint.
    Used by other microservices to validate tokens via the API gateway.
    """
    token_string = request.json.get('token') if request.is_json else request.form.get('token')

    if not token_string:
        return jsonify({'active': False, 'error': 'missing_token'}), 200

    token = AccessToken.query.filter_by(token=token_string).first()

    if token is None or not token.is_valid:
        return jsonify({'active': False}), 200

    return jsonify({
        'active': True,
        'scope': token.scopes,
        'client_id': token.client.client_id,
        'username': token.user.username,
        'user_id': token.user.id,
        'token_type': token.token_type,
        'exp': int(token.expires_at.replace(tzinfo=timezone.utc).timestamp()),
        'iat': int(token.created_at.replace(tzinfo=timezone.utc).timestamp()),
    }), 200


